//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = function () {
    scwin.globalVars();
    scwin.f_Retrieve();
};
//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {
    ds_retrieve.setEmptyValue();//  .clearData();		
    ds_retrieve.set("param1",scwin.param1);
    ds_retrieve.set("param2",scwin.param2);

    $c.sbm.execute(sbm_Retrieve);

};

scwin.btn_Add_onclick = function (e) {
	scwin.f_Attach()
};

scwin.f_Attach = function(){
    let k = 0;
