scwin.sbm_Retrieve_submitdone = function (e) {
//debugger
    if (ds_emp.getRowCount() == 0){
   //     $c.gus.cf
        $c.gus.cfAlertMsg("데이터가 존재하지 않습니다.");
    }
    var parentTransWrkIndictNo = ds_parent.getCellData(scwin.curRow, "transWrkIndictNo");
    var parentTransRsltsSeq = ds_parent.getCellData(scwin.curRow, "transRsltsSeq");

    for(i=0; i< ds_emp.getRowCount(); i++){
        for(j=0; j<=ds_parent.getRowCount(); j++){
            if(ds_parent.getCellData(j, "transWrkIndictNo") == parentTransWrkIndictNo && ds_parent.getCellData(j, "transRsltsSeq") == parentTransRsltsSeq){
                if(ds_parent.getCellData(j, "dcScNm") == ds_emp.getCellData(i,"dcScCdNm")){
                    ds_emp.setCellData(i,"che",1);
                    dcScAmtValue = ds_parent.getCellData(j,"dcScAmt")+"";
                    ds_emp.setCellData(i,"dcScAmt", dcScAmtValue);
                }
            }
        }
    }
    empTotCnt.setValue(ds_emp.getRowCount());  //총건수    
};

